-- Final Security Lockdown: Plug RLS gaps and ensure data ownership across all tables\n\n-- 1. Tighten portfolios SELECT policy (already logic-heavy, but ensure no leaks)\nDROP POLICY IF EXISTS " Portfolios are viewable by everyone if published\ ON public.portfolios;\nCREATE POLICY \Portfolios are viewable by everyone if published\ ON public.portfolios\nFOR SELECT USING (\n status = 'published' \n OR \n (status = 'draft' AND EXISTS (\n SELECT 1 FROM chameleon_links cl \n WHERE cl.user_id = portfolios.user_id AND cl.is_active = true\n ))\n OR \n (user_id = auth.uid())\n);\n\n-- 2. Audit logs (payments, transactions) - Ensure ONLY owner can SELECT\n-- This is already done in 20260312_security_lockdown.sql for transactions,\n-- and 20260306120000_payment_tables.sql for payments.\n\n-- 3. Identity Vault - Re-confirm UPDATE false\nDROP POLICY IF EXISTS \Users cannot arbitrarily update composite score\ ON public.identity_vault;\nCREATE POLICY \Users cannot arbitrarily update composite score\ ON public.identity_vault\n FOR UPDATE USING (false);\n\n-- 4. Storage Cleanup - Ensure no legacy policies exist\nDROP POLICY IF EXISTS \Authenticated users can upload project documents\ ON storage.objects;\nDROP POLICY IF EXISTS \Public Access Photos\ ON storage.objects;\n\n-- 5. Rate Limits - Re-confirm SELECT only for owner, NO public update\nDROP POLICY IF EXISTS \Rate limits are managed by functions only\ ON public.rate_limits;\nCREATE POLICY \Rate limits are managed by functions only\ ON public.rate_limits\nFOR ALL USING (false);\n\nCREATE POLICY \Users can read own rate limits\ ON public.rate_limits\nFOR SELECT USING (auth.uid() = user_id);\n\n-- 6. Chat Queries - Ensure ONLY owner can SELECT\nALTER TABLE public.chat_queries ENABLE ROW LEVEL SECURITY;\nDROP POLICY IF EXISTS \Users can view their own chat queries\ ON public.chat_queries;\nCREATE POLICY \Users can view their own chat queries\ ON public.chat_queries\nFOR SELECT USING (auth.uid() = profile_user_id);\n\n-- 7. User Profiles - Ensure sensitive fields are NEVER modifiable by user\n-- Already handled by protect_pro_fields trigger.\n\n-- 8. Final Check on storage policies (Atomic ownership check)\nCREATE OR REPLACE FUNCTION storage.foldername(name text)\n RETURNS text[]\n LANGUAGE plpgsql\n AS c:\Users\shaik\Downloads\foliogen\nBEGIN\n RETURN string_to_array(name, '/');\nEND;\nc:\Users\shaik\Downloads\foliogen;\n